return items.map((item) => {
  item.json.target_folder = 'vault/00_Inbox';
  item.json.review_routing_reason = 'QA risk checker or classifier required human review.';
  return item;
});

const fs = require('fs');
const path = require('path');

const requiredFields = ['title', 'type', 'community', 'priority', 'effective_date', 'source', 'status', 'tags', 'last_updated', 'version'];

function sanitizeFilename(input) {
  const raw = String(input || 'unclassified-ingestion.md').replace(/\.md$/i, '');
  const cleaned = raw.toLowerCase()
    .replace(/[\\/:*?"<>|]/g, ' ')
    .replace(/[^a-z0-9\s._-]/g, ' ')
    .replace(/[\s._-]+/g, '-')
    .replace(/^-+|-+$/g, '');
  return `${cleaned || 'unclassified-ingestion'}.md`;
}

function validateFrontmatter(markdown) {
  const match = String(markdown || '').match(/^---\r?\n([\s\S]*?)\r?\n---\r?\n?/);
  if (!match) throw new Error('normalized_markdown is missing YAML frontmatter.');
  for (const field of requiredFields) {
    const pattern = new RegExp(`^${field}:`, 'm');
    if (!pattern.test(match[1])) throw new Error(`normalized_markdown is missing frontmatter field: ${field}`);
  }
}

return items.map((item) => {
  const payload = item.json;
  const markdown = String(payload.normalized_markdown || '');
  validateFrontmatter(markdown);

  const vaultRoot = path.resolve(process.env.VAULT_PATH || 'vault');
  const targetFolder = String(payload.target_folder || 'vault/00_Inbox').replace(/\\/g, '/');
  const relativeFolder = targetFolder.replace(/^\.?\/*vault\/*/, '') || '00_Inbox';
  const filename = sanitizeFilename(payload.suggested_filename);
  const destination = path.resolve(vaultRoot, relativeFolder, filename);

  if (destination !== vaultRoot && !destination.startsWith(`${vaultRoot}${path.sep}`)) {
    throw new Error('Refusing to write outside VAULT_PATH.');
  }

  if (fs.existsSync(destination)) {
    throw new Error(`Refusing to overwrite existing file: ${destination}`);
  }

  fs.mkdirSync(path.dirname(destination), { recursive: true });
  fs.writeFileSync(destination, markdown, 'utf8');

  payload.written_file = destination;
  payload.written_filename = filename;
  payload.write_status = 'written';
  return item;
});

